struct Logo { const uint8_t* data; uint16_t size; };

inline const Logo* logoForKey(const String& key) {
  static const Logo tigers{LOGO_TIGERS, LOGO_SIZE};
  static const Logo cubs{LOGO_CUBS, LOGO_SIZE};
  static const Logo lions{LOGO_LIONS, LOGO_SIZE};
  static const Logo pistons{LOGO_PISTONS, LOGO_SIZE};
  static const Logo msu{LOGO_MSU, LOGO_SIZE};
  if (key == "tigers") return &tigers;
  if (key == "cubs") return &cubs;
  if (key == "lions") return &lions;
  if (key == "pistons") return &pistons;
  if (key == "msu-football" || key == "msu-basketball") return &msu;
  return nullptr;
}
